using System.Collections;
using UnityEngine;
using UnityEngine.Scripting.APIUpdating;

/// <summary>
/// Tipo de descoberta permanente de área, registado em
/// PlayerProgress.AreaProgress para a secção "Área Atual" do Menu de Pausa
/// (Tarefa #7 — DESCOBERTAS: Runas/NPCs/Sussurros/Baús/Fragmentos).
/// </summary>
public enum AreaDiscoveryType
{
    RunaDeGaia,
    NpcResgatado,
    SussurroDaTerra,
    BauEncontrado,
    FragmentoVital
}

/// <summary>
/// Regista uma descoberta permanente de "area" (Runa/NPC/Sussurro/Baú/Fragmento)
/// para a secção "Área Atual" do Menu de Pausa. Independente de dar o recurso
/// em si — combinar com Action_GiveResource quando o recurso também deve
/// somar ao saldo global do jogador (ex: Runas de Gaia, Fragmentos Vitais).
/// </summary>
[System.Serializable]
public class Action_AddAreaDiscovery : NpcAction
{
    public AreaData area;
    public AreaDiscoveryType discovery = AreaDiscoveryType.RunaDeGaia;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || area == null) yield break;

        switch (discovery)
        {
            case AreaDiscoveryType.RunaDeGaia:
                progress.AddRunaFound(area);
                break;

            case AreaDiscoveryType.NpcResgatado:
                // Task #21: AddNpcRescued requer npcId para garantir idempotência.
                // Usar Action_RescueNpc (com npcId preenchido) em vez desta acção.
                Debug.LogWarning("[Action_AddAreaDiscovery] NpcResgatado não suportado sem npcId. Usa Action_RescueNpc com o campo npcId preenchido.");
                break;

            case AreaDiscoveryType.SussurroDaTerra:
                // Forma "só contagem" (sem frase) — preferir Action_AddAreaSussurroDaTerra
                // quando houver uma frase de NPC para registar (regista contagem + frase).
                progress.AddWhisperFound(area);
                break;

            case AreaDiscoveryType.BauEncontrado:
                progress.AddChestFound(area);
                break;

            case AreaDiscoveryType.FragmentoVital:
                progress.AddFragmentFound(area);
                break;
        }

        PauseMenuController.Instance?.RefreshHeader_External();
        yield break;
    }
}

/// <summary>
/// Marca o desafio opcional de "area" como descoberto (deixa de mostrar "?" e
/// passa a "Não concluído") e, opcionalmente, como concluído.
/// </summary>
[System.Serializable]
public class Action_SetAreaChallenge : NpcAction
{
    public AreaData area;

    [Tooltip("Se activo, marca o desafio como concluído (e descoberto). Se inactivo, só marca como descoberto — mostra \"Não concluído\" em vez de \"?\".")]
    public bool completed;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || area == null) yield break;

        if (completed) progress.MarkChallengeCompleted(area);
        else progress.MarkChallengeDiscovered(area);

        PauseMenuController.Instance?.RefreshHeader_External();
        yield break;
    }
}

/// <summary>
/// Adiciona um Sussurro da Terra — frase exacta dita por este NPC sobre "area" —
/// à secção "SUSSURROS DA TERRA" da página "Área Atual" do Menu de Pausa, e conta
/// também como um Sussurro da Terra encontrado (mesma colecionável da contagem
/// "Sussurros da Terra" nas Descobertas). A frase NÃO é gerada automaticamente:
/// deve ser escrita tal como o NPC a diz no diálogo.
/// </summary>
[System.Serializable]
[MovedFrom(true, sourceClassName: "Action_AddAreaEcho")]
public class Action_AddAreaSussurroDaTerra : NpcAction
{
    public AreaData area;

    [TextArea]
    public string phrase;

    public override IEnumerator Execute(NpcController npc)
    {
        if (area == null || string.IsNullOrEmpty(phrase)) yield break;

        PlayerProgress.Instance?.AddSussurroDaTerra(area, phrase);
        PauseMenuController.Instance?.RefreshHeader_External();
        yield break;
    }
}
